import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Page } from '../components/Layout';
import { CARS } from '../mockCars';

export default function HomePage() {
  const navigate = useNavigate();

  return (
    <Page
      title="Drive Your Next Trip"
      subtitle="Book cars online, track your requests, and manage approvals from one place."
    >
      <section className="grid cards3">
        {CARS.map((car) => (
          <article className="card carCard" key={car.id}>
            <img src={car.image} alt={car.name} className="carImage" />
            <div className="tag">{car.badge}</div>
            <h3>{car.name}</h3>
            <p>{car.company} • {car.fuelType} • {car.seats} seats</p>
            <div className="cardRow">
              <strong>₹{car.rentPerDay.toLocaleString()}/day</strong>
              <button className="button" onClick={() => navigate(`/car/detail/${car.id}`)}>
                Book Now
              </button>
            </div>
          </article>
        ))}
      </section>
    </Page>
  );
}
